def main():
    class FileSaver:

        def save(self, data):
            print(f'Saved to file: {data}')

    class ConsoleSaver:

        def save(self, data):
            print(data)

    def store_data(saver, data):
        saver.save(data)

    file_saver = FileSaver()

    console_saver = ConsoleSaver()

    store_data(file_saver, 'Data to save')

    store_data(console_saver, 'Data to save')

if __name__ == "__main__":
    main()

