def main():
    class Pen:

        def write(self):
            print('Writing with a pen.')

    class Keyboard:

        def write(self):
            print('Typing with a keyboard.')

    def compose(writer):
        writer.write()

    pen = Pen()

    keyboard = Keyboard()

    compose(pen)

    compose(keyboard)

if __name__ == "__main__":
    main()

