def main():
    class Dog:

        def bark(self):
            print('Woof!')

    def pet_speak(pet):
        if hasattr(pet, 'bark'):
            pet.bark()
        else:
            print("This pet doesn't bark.")

    dog = Dog()

    pet_speak(dog)

    pet_speak("I'm not a pet")

if __name__ == "__main__":
    main()

