problems.solution:
def main():
    class Car:

        def drive(self):
            print('Car is driving.')

    def start_trip(vehicle):
        vehicle.drive()

    car = Car()

    start_trip(car)

    bicycle = "I'm a bicycle"

    try:
        start_trip(bicycle)
    except AttributeError as error:
        print(f'AttributeError: {error}')

if __name__ == "__main__":
    main()

